Using Click for a clean CLI with subcommands:

```python
import click
import json
from pathlib import Path
from datetime import datetime

DB = Path.home() / '.todo.json'

def load_todos():
    if not DB.exists():
        return []
    return json.loads(DB.read_text())

def save_todos(todos):
    DB.write_text(json.dumps(todos, indent=2))

@click.group()
def cli():
    """Simple to-do list manager."""
    pass

@cli.command()
@click.argument('task')
@click.option('-p', '--priority', type=click.Choice(['high', 'medium', 'low']), default='medium')
def add(task, priority):
    """Add a new task."""
    todos = load_todos()
    todos.append({
        'id': len(todos) + 1,
        'task': task,
        'priority': priority,
        'done': False,
        'created': datetime.now().isoformat()
    })
    save_todos(todos)
    click.echo(f'Added: {task} [{priority}]')

@cli.command('list')
@click.option('-a', '--all', 'show_all', is_flag=True)
@click.option('-p', '--priority', help='Filter by priority')
def list_tasks(show_all, priority):
    """List tasks."""
    todos = load_todos()
    filtered = [t for t in todos if show_all or not t['done']]
    if priority:
        filtered = [t for t in filtered if t['priority'] == priority]
    for t in filtered:
        status = 'done' if t['done'] else 'todo'
        click.echo(f"  [{status}] {t['id']}: {t['task']} ({t['priority']})")

@cli.command()
@click.argument('task_id', type=int)
def done(task_id):
    """Mark task as done."""
    todos = load_todos()
    for t in todos:
        if t['id'] == task_id:
            t['done'] = True
            save_todos(todos)
            click.echo(f'Task {task_id} marked done')
            return
    click.echo(f'Task {task_id} not found')

@cli.command()
@click.argument('task_id', type=int)
def delete(task_id):
    """Delete a task."""
    todos = load_todos()
    todos = [t for t in todos if t['id'] != task_id]
    save_todos(todos)
    click.echo(f'Deleted task {task_id}')

if __name__ == '__main__':
    cli()
```

